var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"클리포트 게임 종료 직후","JPN":"クリフォトゲーム終了直後","ENG":"Right after the Qliphoth Game ended","TWN":"逆卡巴拉遊戲結束後，","DEU":"Right after the Qliphoth Game ended","FRA":"Right after the Qliphoth Game ended"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 공략 요청 고심도 좌표 <color=#ffd34c>그림자 전당</color>","JPN":"管理局攻略要請高深度座標、<color=#ffd34c>影の殿堂</color>","ENG":"Administration Assault Request Hyperdepth Coordinates, <color=#ffd34c>Shadow Palaces</color>","TWN":"管理局攻略請求高深度座標<color=#ffd34c>暗影殿堂</color>","DEU":"Administration Assault Request Hyperdepth Coordinates, <color=#ffd34c>Shadow Palaces</color>","FRA":"Administration Assault Request Hyperdepth Coordinates, <color=#ffd34c>Shadow Palaces</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"……팩토리 쉽의 잔해를 발견했다.","JPN":"……ファクトリーシップの残骸を発見。","ENG":"...We have found the wreckage of the Factory Ship.","TWN":"……發現了工廠艦的殘骸。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"엔진을 과열시켜 자폭했지만, 예상대로 상당 부분 쓸만한 파츠가 남아있군.","JPN":"エンジン過熱で自爆したが、予想通り使えるパーツは結構残っている。","ENG":"It overheated its engine and self-destructed, yet as expected, a considerable number of usable parts remain.","TWN":"雖然它因為引擎過熱自爆，但正如預期，仍留下許多可用的零件。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"AI 알고리즘 파악 중. 불필요한 파츠는 분해 후, 재구성 프로세스를 진행한다.","JPN":"AIアルゴリズムを把握中。不要なパーツは分解し、再構成プロセスを進行する。","ENG":"Parsing the AI algorithms. Dismantle unnecessary parts, then commence the reconfiguration process.","TWN":"目前正在解析AI演算法。拆解不需要的零件後，進行重建的流程。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"핵심 설비를 전부 재생하기 위해서는 상당한 시간이 필요하겠지만.","JPN":"核心設備をすべて再生するには、相当な時間がかかるだろうが。","ENG":"Restoring all core facilities will take substantial time.","TWN":"雖然要全面重建核心設備還需要很長一段時間。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"진정한 진화를 이룩하기 위해서라면…….","JPN":"真の進化を遂げるためとあれば……","ENG":"But if it is for true evolution...","TWN":"但若是為了達成真正的進化……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"역시 이곳에 계셨군요.","JPN":"やはりここにいらしたんですね。","ENG":"I knew you would be here.","TWN":"您果然在這裡啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_QM","text":{"KOREA":"너는……?","JPN":"お前は……？","ENG":"And you are...?","TWN":"你是……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"알파트릭스가 초거대 그룹으로 성장한 뒤…….","JPN":"アルファトリックスが超巨大グループに成長した後……","ENG":"After Alphatrix grew into a mega-conglomerate...","TWN":"自從阿爾法崔克斯成為超大型集團後……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버지께서 가장 먼저 하신 일은 완전 자율 AI로 움직이는 생산기지의 건조였어요.","JPN":"お祖父様が真っ先に着手されたのが、完全自立型AIで動く生産基地の建造でした。","ENG":"The very first thing my grandfather did was construct a fully autonomous production base run by AI.","TWN":"祖父第一件做的事，就是建造由全自律AI運行的生產基地。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이면세계를 무작위로 다이브하며, 스스로 이터니움을 확보 및 가공하는 팩토리 쉽.","JPN":"裏世界をランダムにダイブし、自らエタニウムを確保・加工するファクトリーシップ。","ENG":"A Factory Ship that dives the Counterside at random and secures and refines Eternium on its own.","TWN":"能任意潛入異世界，自主取得並加工永恆之金的工廠艦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"더 나은 세상을 위해, 그건 반드시 필요한 일이었을 거예요.","JPN":"より良い世界のために、それは必要不可欠なことだったのでしょう。","ENG":"For a better world, it was something we absolutely needed.","TWN":"為了更好的世界，那是必要的工程。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 알파트릭스라고 해도, 느닷없이 그런 엄청난 함선을 제작할 기술력은 없었죠.","JPN":"ただ、いくらアルファトリックスといえ、突然そんな艦船を作る技術力は持っていなかった。","ENG":"But even Alphatrix didn't have the tech to suddenly build a ship of that scale.","TWN":"但就算是阿爾法崔克斯，也不可能突然具備打造那種巨艦的技術。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서 할아버지께서는 퓨처 앳 워와 기술적 제휴를 맺으셨어요.","JPN":"だからお祖父様はフューチャーアットウォーと技術提携を結びました。","ENG":"So my grandfather entered a technical partnership with Future-at-War.","TWN":"所以祖父與天啟兵器簽訂技術合作。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"바로 이곳에서 파괴된 <color=#ffd34c>오비탈 베이스</color>의 제작을 위해서.","JPN":"他でもない、ここで破壊された<color=#ffd34c>オービタルベース</color>を作るために。","ENG":"To build the <color=#ffd34c>Orbital Base</color> that was later destroyed here.","TWN":"就是為了在這裡打造破壞的<color=#ffd34c>軌道基地</color>。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……그렇지 않나요, <color=#ffd34c>엠버</color> 박사님?","JPN":"……そうですよね？　<color=#ffd34c>アンバー</color>博士。","ENG":"...Isn't that right, Dr. <color=#ffd34c>Ember</color>?","TWN":"……不是嗎，<color=#ffd34c>琥珀</color>博士？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"허수 공간에서 일부러 통신 채널을 개방했던 건, 내 본체의 위치를 역추적하기 위함이었나?","JPN":"虚数空間でわざわざ通信チャンネルを開放したのは、私の本体を逆追跡するためだったのか？","ENG":"You deliberately opened a comms channel in the imaginary space to back-trace the location of my core body.","TWN":"故意在量子空間開放通訊頻道，是為了反追蹤我本體的位置嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"여기까지 계산해 두다니, 역시 빈틈이 없군. 알파트릭스 회장이 남긴 괴물다워.","JPN":"ここまで計算するとは隙がないな。さすがアルファトリックス会長が残した化け物だ。","ENG":"To have calculated this far... no loose ends indeed. Fitting for the monster Alphatrix's late President left behind.","TWN":"能預先算到這一步，果然無懈可擊。不愧是阿爾法崔克斯會長留下的怪物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 이미 그룹의 회장직을 계승했답니다.","JPN":"私はすでに会長職を継承していますよ。","ENG":"I have already inherited that position.","TWN":"我已經繼承了集團的會長職位。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후후, 그래도 괴물이라 불리는 건, 역시 서운하네요.","JPN":"ふふ……でも化け物だと呼ばれるのは、やはり悲しいですね。","ENG":"Haha, still, being called a \\"monster\\" does sting a little.","TWN":"呵呵，但被稱作怪物，還是有點委屈呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"아무것도 느끼지 못하는 주제에, 인간인 척 행세하는 건가?","JPN":"何も感じない作り物の器で、人間ぶるつもりか？","ENG":"You feel nothing, yet you pretend to be human?","TWN":"你明明什麼都感覺不到，現在是在扮演人類嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 왜냐하면 저는 인간이니까요.","JPN":"はい、なぜなら私は人間ですから。","ENG":"Yes, because I am human.","TWN":"對，因為我本來就是人類。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 그건 당신도 마찬가지라고 생각해요, 엠버 박사님.","JPN":"それはあなたも同じだと思いますよ、アンバー博士。","ENG":"And I think that applies to you as well, Dr. Ember.","TWN":"而且我認為這點妳也一樣，琥珀博士。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"착각하지 마라. 인간 시절의 나약한 육체와 이름은 이미 버린 지 오래다.","JPN":"思い違いにも甚だしい。人間だった頃の脆弱な肉体と名前はとうに捨てた。","ENG":"Do not delude yourself. I discarded that frail human body and name long ago.","TWN":"妳別誤會了。我早就放棄人類時期那軟弱的軀體與名字。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 인간은 실패로부터 깨닫고, 현실을 바꿀 힘을 가지고 있는 걸요.","JPN":"でも人間は失敗から学び、現実を変える力を持っています。","ENG":"Yet humans learn from failure and have the power to change reality.","TWN":"但人類會從失敗中領悟，進而擁有改變現實的力量。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그건 사장님도, 저도, 그리고 당신도 마찬가지죠.","JPN":"それは社長も、私も、あなたも同じ。","ENG":"That is true for Boss, for me, and for you.","TWN":"這點不只是老闆，我，還有你都一樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"인간이기 위해서, 이름과 겉모습 같은 건 중요하지 않다고 생각해요.","JPN":"人間であるために、名前や見た目は関係ないと思います。","ENG":"To be human, names and outer forms don't matter.","TWN":"為了做個真正的人類，我認為名字和外表這些並不重要。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"중요한 건… 그래요, <color=#ffd34c>마음</color>이죠.","JPN":"大事なのは……そう、<color=#ffd34c>心</color>です。","ENG":"What matters is... Yes, the <color=#ffd34c>heart</color>.","TWN":"重要的是……沒錯，是<color=#ffd34c>心</color>。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"마음……?","JPN":"心……？","ENG":"The heart...?","TWN":"心……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"실패에 굴하지 않고, <color=#ffd34c>더 나은 세상을 위해</color> 스스로 나아가려는 의지.","JPN":"失敗しても屈せず、<color=#ffd34c>より良い世界のために</color>前へ進もうとする意志。","ENG":"The will to keep moving forward <color=#ffd34c>for a better world</color> without bowing to failure.","TWN":"不因失敗屈服，為了<color=#ffd34c>更好的未來</color>勇於前進的意志。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저는 그게 제 마음의 형태라고 정의했어요.","JPN":"私は、それが自分の心の形だと定義しました。","ENG":"That is how I define the shape of my heart.","TWN":"我把這定義為我自己內心的形態。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"과거, 당신이 어떤 실수를 저질렀고, 어째서 그런 모습이 되었는지는 모르겠지만.","JPN":"過去にあなたがどんな間違いを犯したのか、なぜそのような姿になったのかは分かりませんが。","ENG":"I do not know what mistake you made in the past, or why you became like this.","TWN":"雖然我不清楚過去你犯了什麼錯、為什麼會變成那副模樣。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"과거의 약점을 극복하고, 진화를 멈추지 않으려는 그 알고리즘이야 말로…….","JPN":"過去の弱点を乗り越え、進化し続けようとするそのアルゴリズムこそ……","ENG":"But that algorithm which strives to overcome past weakness and never cease evolving...","TWN":"但克服過去的弱點、持續進化的演算法……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"당신을 한층 더 인간답게 만들어주는 마음이라고 할 수 있지 않을까요?","JPN":"あなたをより一層人間らしくする心だと言えるんじゃないでしょうか？","ENG":"Couldn't that be the heart that makes you more human?","TWN":"才是讓你更像人類的心吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"……자기변호에서 파생된 역겨운 궤변이로군, 괴물.","JPN":"……自己弁護から派生した、反吐が出るような詭弁だな、化け物。","ENG":"...A disgusting sophistry born from self-justification, monster.","TWN":"……原來是從自我辯護派生出的噁心謬論啊，怪物。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L4_1","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"L26_1"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"L51_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L4_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"L38_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L4_1","slots":{"L":null,"C":{"char_id":"L38_1","face":"L38_1"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"L14_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L48_1","slots":{"L":null,"C":{"char_id":"L14_1","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"L48_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L48_1","slots":{"L":null,"C":{"char_id":"L48_1","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};